{"content": "     1|import AppKit
     2|import Foundation
     3|import SwiftUI
     4|
     5|@MainActor
     6|final class MinifyViewModel: ObservableObject {
     7|    @Published var images: [InputImage] = []
     8|    @Published var outputFormat: OutputFormat = .webp
     9|    @Published var quality: Double = 0.72
    10|    @Published var estimatedSize: Int64 = 0
    11|    @Published var conversionResults: [ConversionResult] = []
    12|    @Published var isConverting = false
    13|    @Published var conversionProgress: Double = 0
    14|    @Published var statusMessage: String = "Drop or pick images to begin."
    15|    @Published var lastError: String?
    16|
    17|    private let service = ImageConversionService()
    18|
    19|    func pickImages() {
    20|        let panel = NSOpenPanel()
    21|        panel.canChooseFiles = true
    22|        panel.canChooseDirectories = false
    23|        panel.allowsMultipleSelection = true
    24|        panel.allowedContentTypes = [.image]
    25|
    26|        if panel.runModal() == .OK {
    27|            addImageURLs(panel.urls)
    28|        }
    29|    }
    30|
    31|    func clearImages() {
    32|        images.removeAll()
    33|        conversionResults.removeAll()
    34|        conversionProgress = 0
    35|        recalculateEstimate()
    36|        statusMessage = "Selection cleared."
    37|    }
    38|
    39|    func removeImage(_ image: InputImage) {
    40|        images.removeAll { $0.url.path == image.url.path }
    41|        conversionResults.removeAll { $0.source.path == image.url.path }
    42|        recalculateEstimate()
    43|        statusMessage = "Removed \(image.url.lastPathComponent)."
    44|    }
    45|
    46|    func addImageURLs(_ urls: [URL]) {
    47|        let fresh = urls.compactMap { url -> InputImage? in
    48|            guard let attrs = try? FileManager.default.attributesOfItem(atPath: url.path),
    49|                  let size = (attrs[.size] as? NSNumber)?.int64Value else { return nil }
    50|            return InputImage(url: url, byteCount: size)
    51|        }
    52|
    53|        var map: [String: InputImage] = [:]
    54|        for item in images + fresh {
    55|            map[item.url.path] = item
    56|        }
    57|        images = map.values.sorted { $0.url.lastPathComponent < $1.url.lastPathComponent }
    58|        recalculateEstimate()
    59|        statusMessage = "Loaded \(images.count) image(s)."
    60|    }
    61|
    62|    func recalculateEstimate() {
    63|        estimatedSize = service.estimateOutputBytes(for: images, format: outputFormat, quality: quality)
    64|    }
    65|
    66|    func convertAll() {
    67|        guard !images.isEmpty else {
    68|            statusMessage = "Select at least one image first."
    69|            return
    70|        }
    71|
    72|        let panel = NSOpenPanel()
    73|        panel.canChooseFiles = false
    74|        panel.canChooseDirectories = true
    75|        panel.canCreateDirectories = true
    76|        panel.prompt = "Choose Output Folder"
    77|
    78|        guard panel.runModal() == .OK, let folder = panel.url else { return }
    79|
    80|        isConverting = true
    81|        conversionProgress = 0
    82|        lastError = nil
    83|        statusMessage = "Converting \(images.count) image(s)..."
    84|
    85|        Task {
    86|            do {
    87|                let totalCount = images.count
    88|                let results = try service.convert(images: images, format: outputFormat, quality: quality, outputFolder: folder) { done, total, latestURL in
    89|                    Task { @MainActor in
    90|                        self.conversionProgress = total > 0 ? Double(done) / Double(total) : 0
    91|                        self.statusMessage = "Converting \(done)/\(total): \(latestURL.lastPathComponent)"
    92|                    }
    93|                }
    94|                conversionResults = results
    95|                let totalIn = results.reduce(Int64(0)) { $0 + $1.originalBytes }
    96|                let totalOut = results.reduce(Int64(0)) { $0 + $1.outputBytes }
    97|                conversionProgress = totalCount > 0 ? 1 : 0
    98|                statusMessage = "Done. \(ByteCountFormatter.string(fromByteCount: totalIn, countStyle: .file)) → \(ByteCountFormatter.string(fromByteCount: totalOut, countStyle: .file))"
    99|            } catch {
   100|                lastError = error.localizedDescription
   101|                statusMessage = "Conversion failed."
   102|            }
   103|            isConverting = false
   104|        }
   105|    }
